FILES = {'src/frontend/command_center/modern/index.html': '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>Claire Syntalion — Strategic Operator Cockpit</title>\n  <link rel="stylesheet" href="claire_strategic_cockpit.css" />\n</head>\n<body>\n  <div id="claire-app" class="claire-app">\n    <aside class="claire-sidebar">\n      <div class="brand-block">\n        <div class="brand-kicker">Claire Syntalion</div>\n        <div class="brand-name">CLAIRE</div>\n        <div class="brand-subtitle">Strategic Intelligence Cockpit</div>\n\n        <div id="claire-search" class="search-shell">\n          <div class="search-box">\n            <input id="claire-search-input" type="search" autocomplete="off" spellcheck="false" placeholder="Ask Claire about opportunities, paths, packages…" />\n            <button id="claire-mic-button" class="mic-button" type="button" aria-label="Use microphone">\n              <span aria-hidden="true">◉</span>\n            </button>\n          </div>\n          <div id="claire-search-results" class="search-results"></div>\n        </div>\n      </div>\n\n      <div class="sidebar-status-grid">\n        <div class="mini-card">\n          <div id="side-mission" class="mini-value">No mission loaded</div>\n          <div class="mini-label">Mission</div>\n        </div>\n        <div class="mini-card">\n          <div id="side-path" class="mini-value">Awaiting signal</div>\n          <div class="mini-label">Path</div>\n        </div>\n        <div class="mini-card">\n          <div id="side-readiness" class="mini-value">Not ready</div>\n          <div class="mini-label">Readiness</div>\n        </div>\n        <div class="mini-card">\n          <div id="side-trust" class="mini-value">Unverified</div>\n          <div class="mini-label">Trust</div>\n        </div>\n      </div>\n\n      <nav class="sidebar-nav" aria-label="Claire strategic operator sections">\n        <a href="#mission" class="nav-item active"><span>01</span> Mission Control</a>\n        <a href="#brief" class="nav-item"><span>02</span> Opportunity Brief</a>\n        <a href="#path" class="nav-item"><span>03</span> Strategic Path</a>\n        <a href="#portfolio" class="nav-item"><span>04</span> Portfolio</a>\n        <a href="#breakthrough" class="nav-item"><span>05</span> Breakthrough</a>\n        <a href="#acquisition" class="nav-item"><span>06</span> Acquisition</a>\n        <a href="#trust" class="nav-item"><span>07</span> Trust</a>\n        <a href="#continuity" class="nav-item"><span>08</span> Continuity</a>\n      </nav>\n    </aside>\n\n    <main class="claire-main">\n      <header class="hero">\n        <div>\n          <div class="hero-kicker">Strategic Operator Cockpit</div>\n          <h1>From Signal to Strategic Package</h1>\n          <p>Discover opportunities, choose the correct path, review outputs, verify trust, and prepare acquisition-ready intelligence.</p>\n        </div>\n        <div class="hero-pills">\n          <span class="hero-pill cyan">Signal → Thesis</span>\n          <span class="hero-pill blue">Portfolio</span>\n          <span class="hero-pill red">Breakthrough</span>\n          <span class="hero-pill orange">Acquisition</span>\n          <span class="hero-pill green">Verified</span>\n        </div>\n      </header>\n\n      <section id="mission" class="mission-panel">\n        <div class="mission-copy">\n          <div class="panel-kicker">Mission Control</div>\n          <h2 id="mission-title">No active mission loaded</h2>\n          <p id="mission-summary">Claire is ready, but no completed mission output has been loaded into the cockpit yet.</p>\n        </div>\n        <div class="mission-actions">\n          <button id="refresh-state" class="primary-button" type="button">Refresh Cockpit</button>\n          <button id="diagnostics-toggle" class="secondary-button" type="button">Diagnostics</button>\n        </div>\n      </section>\n\n      <section id="brief" class="panel">\n        <div class="panel-header">\n          <div>\n            <div class="panel-kicker">Opportunity Brief</div>\n            <h2>What Claire Is Seeing</h2>\n            <p>Operator summary of the loaded mission, signal strength, thesis state, and next review requirement.</p>\n          </div>\n          <span id="brief-pill" class="status-pill amber">Awaiting mission</span>\n        </div>\n\n        <div class="brief-grid">\n          <div class="brief-card primary">\n            <div class="card-label">Current Objective</div>\n            <div id="brief-objective" class="card-value">Load or generate a Claire mission</div>\n            <div id="brief-objective-note" class="card-note">The cockpit will not invent an opportunity without a run output.</div>\n          </div>\n          <div class="brief-card">\n            <div class="card-label">Strategic Thesis</div>\n            <div id="brief-thesis" class="card-value">No thesis available</div>\n            <div class="card-note">Generated after signal consolidation and insight structuring.</div>\n          </div>\n          <div class="brief-card">\n            <div class="card-label">Signal State</div>\n            <div id="brief-signal" class="card-value">Awaiting signal</div>\n            <div class="card-note">Source-governed signals drive path selection.</div>\n          </div>\n          <div class="brief-card">\n            <div class="card-label">Recommended Review</div>\n            <div id="brief-review" class="card-value">Load mission output</div>\n            <div class="card-note">Outputs become actionable only after trust review.</div>\n          </div>\n        </div>\n      </section>\n\n      <section id="path" class="panel">\n        <div class="panel-header">\n          <div>\n            <div class="panel-kicker">Strategic Path</div>\n            <h2>Which Route Did Claire Choose?</h2>\n            <p>Claire should default to useful portfolio intelligence, escalate only when signals justify breakthrough/design work, and build acquisition packages only when strategic fit exists.</p>\n          </div>\n          <span id="path-pill" class="status-pill amber">Awaiting signal</span>\n        </div>\n\n        <div class="route-grid">\n          <article id="route-portfolio" class="route-card blue">\n            <div class="route-badge">Default</div>\n            <h3>Portfolio Intelligence</h3>\n            <p>Thesis update, opportunity watch, portfolio action, optimization, or risk response.</p>\n            <div id="route-portfolio-state" class="route-state">Awaiting signal</div>\n          </article>\n          <article id="route-breakthrough" class="route-card red">\n            <div class="route-badge">Conditional</div>\n            <h3>Breakthrough / Design</h3>\n            <p>Gap discovery, solution generation, buildability, viability, feasibility, and design portal output.</p>\n            <div id="route-breakthrough-state" class="route-state">Not selected</div>\n          </article>\n          <article id="route-acquisition" class="route-card orange">\n            <div class="route-badge">Strategic</div>\n            <h3>Acquisition Package</h3>\n            <p>Moat, strategic positioning, acquirer fit, acquisition rationale, and final package readiness.</p>\n            <div id="route-acquisition-state" class="route-state">Not selected</div>\n          </article>\n        </div>\n      </section>\n\n      <div class="operator-grid">\n        <section id="portfolio" class="panel">\n          <div class="panel-kicker">Portfolio Desk</div>\n          <h2>Portfolio Actions</h2>\n          <div id="portfolio-content" class="operator-card-list"></div>\n        </section>\n\n        <section id="breakthrough" class="panel">\n          <div class="panel-kicker red-text">Breakthrough Studio</div>\n          <h2>Design & Build Path</h2>\n          <div id="breakthrough-content" class="operator-card-list"></div>\n        </section>\n      </div>\n\n      <section id="acquisition" class="panel">\n        <div class="panel-header">\n          <div>\n            <div class="panel-kicker orange-text">Acquisition Room</div>\n            <h2>Acquisition Readiness</h2>\n            <p>Review strategic fit, moat, differentiation, acquirer rationale, and package status.</p>\n          </div>\n          <span id="acquisition-pill" class="status-pill amber">Not ready</span>\n        </div>\n\n        <div class="brief-grid three">\n          <div class="brief-card">\n            <div class="card-label">Package State</div>\n            <div id="acq-package" class="card-value">No package loaded</div>\n          </div>\n          <div class="brief-card">\n            <div class="card-label">Acquirer Fit</div>\n            <div id="acq-fit" class="card-value">Not evaluated</div>\n          </div>\n          <div class="brief-card">\n            <div class="card-label">Strategic Rationale</div>\n            <div id="acq-rationale" class="card-value">Not available</div>\n          </div>\n        </div>\n      </section>\n\n      <div class="operator-grid">\n        <section id="trust" class="panel trust-panel">\n          <div class="panel-header">\n            <div>\n              <div class="panel-kicker">Trust Gate</div>\n              <h2>Is It Safe to Act On?</h2>\n              <p>Evidence, verification, and unsupported claims are shown as operator trust signals.</p>\n            </div>\n            <span id="trust-pill" class="status-pill amber">Unverified</span>\n          </div>\n          <div class="brief-grid two">\n            <div class="brief-card">\n              <div class="card-label">Confidence</div>\n              <div id="trust-score" class="card-value">0/100</div>\n            </div>\n            <div class="brief-card">\n              <div class="card-label">Evidence</div>\n              <div id="trust-evidence" class="card-value">0 item(s)</div>\n            </div>\n            <div class="brief-card wide">\n              <div class="card-label">Trust Message</div>\n              <div id="trust-message" class="card-value small">No verified mission output loaded.</div>\n            </div>\n          </div>\n        </section>\n\n        <section id="continuity" class="panel continuity-panel">\n          <div class="panel-header">\n            <div>\n              <div class="panel-kicker purple-text">Continuity</div>\n              <h2>Can Claire Reuse It?</h2>\n              <p>Only verified, eligible outputs may become continuity for future Claire reasoning.</p>\n            </div>\n            <span id="continuity-pill" class="status-pill amber">Not ready</span>\n          </div>\n          <div class="brief-grid two">\n            <div class="brief-card">\n              <div class="card-label">Continuity</div>\n              <div id="continuity-state" class="card-value">Not ready</div>\n            </div>\n            <div class="brief-card">\n              <div class="card-label">Future Use</div>\n              <div id="future-use" class="card-value">Blocked</div>\n            </div>\n            <div class="brief-card wide">\n              <div class="card-label">Reason</div>\n              <div id="continuity-reason" class="card-value small">Claire needs verified output before continuity can be enabled.</div>\n            </div>\n          </div>\n        </section>\n      </div>\n\n      <section id="next-actions" class="panel">\n        <div class="panel-header">\n          <div>\n            <div class="panel-kicker">Next Operator Actions</div>\n            <h2>What Should Happen Next?</h2>\n            <p>Plain-English action guidance based on the loaded mission state.</p>\n          </div>\n        </div>\n        <div id="action-list" class="operator-card-list"></div>\n      </section>\n\n      <details id="developer-diagnostics" class="diagnostics">\n        <summary>Developer diagnostics</summary>\n        <div class="diagnostic-grid">\n          <code>python tools/claire_build_runtime_truth.py</code>\n          <code>python tools/claire_validate_runtime_truth.py</code>\n          <code>python tools/claire_build_verified_memory.py</code>\n          <code>python tools/claire_build_dashboard_search_index.py</code>\n        </div>\n        <pre id="diagnostic-json">{}</pre>\n      </details>\n\n      <footer class="proofbar">\n        <div><span>Mission</span><strong id="proof-mission">No mission loaded</strong></div>\n        <div><span>Path</span><strong id="proof-path">Awaiting signal</strong></div>\n        <div><span>Readiness</span><strong id="proof-readiness">Not ready</strong></div>\n        <div><span>Trust</span><strong id="proof-trust">Unverified</strong></div>\n        <div><span>Continuity</span><strong id="proof-continuity">Not ready</strong></div>\n      </footer>\n    </main>\n  </div>\n\n  <script src="claire_strategic_cockpit.js"></script>\n</body>\n</html>\n', 'src/frontend/command_center/modern/claire_strategic_cockpit.css': ':root {\n  --bg:#070d19;\n  --panel:rgba(9,16,31,.92);\n  --panel2:rgba(13,20,38,.84);\n  --border:rgba(0,212,255,.22);\n  --border-soft:rgba(148,163,184,.16);\n  --text:#dce8f7;\n  --muted:#93a4ba;\n  --cyan:#00d4ff;\n  --blue:#60a5fa;\n  --red:#f87171;\n  --orange:#fb923c;\n  --purple:#c084fc;\n  --green:#22c55e;\n  --amber:#f59e0b;\n  --radius:22px;\n  --font-display:Orbitron,"Segoe UI",system-ui,sans-serif;\n  --font:Inter,"Segoe UI",system-ui,sans-serif;\n}\n\n*{box-sizing:border-box}\nhtml,body{min-height:100%;margin:0;color:var(--text);font-family:var(--font);background:radial-gradient(circle at top right,rgba(168,85,247,.16),transparent 38%),linear-gradient(135deg,#06121d,#070d19 48%,#060713);overflow-x:hidden}\nbody::before{content:"";position:fixed;inset:0;pointer-events:none;background-image:linear-gradient(rgba(0,212,255,.026) 1px,transparent 1px),linear-gradient(90deg,rgba(0,212,255,.026) 1px,transparent 1px);background-size:44px 44px;opacity:.55}\n\n.claire-app{position:relative;z-index:1;display:grid;grid-template-columns:430px minmax(0,1fr);gap:20px;min-height:100vh;padding:22px}\n.claire-sidebar{position:sticky;top:22px;align-self:start;max-height:calc(100vh - 44px);overflow:auto;border:1px solid var(--border);border-radius:var(--radius);background:rgba(7,15,29,.88)}\n.brand-block{padding:28px 28px 18px;border-bottom:1px solid rgba(148,163,184,.10)}\n.brand-kicker,.panel-kicker,.hero-kicker{color:var(--cyan);font-family:var(--font-display);font-size:12px;font-weight:900;text-transform:uppercase;letter-spacing:.18em}\n.brand-name{margin-top:12px;color:#e8fbff;font-family:var(--font-display);font-size:45px;font-weight:950;letter-spacing:.22em}\n.brand-subtitle{margin-top:8px;color:var(--muted);font-size:13px;letter-spacing:.12em;text-transform:uppercase}\n\n.search-shell{position:relative;margin-top:20px}\n.search-box{display:flex;align-items:center;gap:8px;min-height:50px;padding:8px 10px 8px 14px;border:1px solid rgba(0,212,255,.30);border-radius:18px;background:rgba(2,10,20,.78)}\n.search-box input{flex:1;min-width:0;border:0;outline:0;background:transparent;color:#f8fafc;font-size:13px}\n.search-box input::placeholder{color:#66758a}\n.mic-button{width:36px;height:36px;border-radius:999px;border:1px solid rgba(0,212,255,.30);color:var(--cyan);background:rgba(0,212,255,.08);cursor:pointer}\n.mic-button.listening{color:var(--green);border-color:rgba(34,197,94,.7)}\n.mic-button[disabled]{opacity:.45;cursor:not-allowed}\n.search-results{display:none;position:absolute;left:0;right:0;top:calc(100% + 8px);z-index:1000;max-height:520px;overflow:auto;padding:8px;border:1px solid rgba(0,212,255,.24);border-radius:18px;background:rgba(3,8,18,.98)}\n.search-results.open{display:block}\n.search-result{width:100%;text-align:left;border:1px solid var(--border-soft);border-radius:14px;margin:6px 0;padding:10px 12px;background:rgba(15,23,42,.52);color:var(--text);cursor:pointer}\n.search-result:hover{border-color:rgba(0,212,255,.46);background:rgba(0,212,255,.08)}\n.search-result-title{font-weight:900;font-size:13px}.search-result-meta{margin-top:3px;color:#7dd3fc;font-size:10px;letter-spacing:.06em;text-transform:uppercase}.search-result-snippet{margin-top:6px;color:var(--muted);font-size:12px;line-height:1.45}\n\n.sidebar-status-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;padding:22px 28px}\n.mini-card{min-height:88px;padding:14px;border:1px solid var(--border-soft);border-radius:16px;background:rgba(15,23,42,.46)}\n.mini-value{font-weight:950;color:#f8fafc;word-break:break-word;line-height:1.25}\n.mini-label{margin-top:8px;color:var(--muted);text-transform:uppercase;letter-spacing:.16em;font-size:10px}\n\n.sidebar-nav{padding:12px 20px 24px}\n.nav-item{display:flex;align-items:center;gap:12px;min-height:48px;padding:10px 14px;color:#b8c6d8;text-decoration:none;border-radius:14px;font-weight:850}\n.nav-item span{display:inline-flex;align-items:center;justify-content:center;min-width:38px;min-height:28px;border:1px solid rgba(0,212,255,.28);border-radius:10px;color:var(--cyan);font-family:var(--font-display);font-size:11px}\n.nav-item.active,.nav-item:hover{background:rgba(0,212,255,.08);color:#f8fafc}\n\n.claire-main{min-width:0;padding-bottom:110px}\n.hero,.panel,.mission-panel{border:1px solid var(--border);border-radius:var(--radius);background:linear-gradient(135deg,rgba(8,15,29,.94),rgba(11,19,36,.88))}\n.hero{display:flex;align-items:flex-start;justify-content:space-between;gap:18px;padding:24px 30px;margin-bottom:20px}\n.hero h1,.panel h2,.mission-panel h2{margin:6px 0 0;color:#eef7ff;font-family:var(--font-display);font-weight:950;letter-spacing:.06em;line-height:1.16}\n.hero h1{font-size:clamp(26px,2.4vw,38px)}.panel h2,.mission-panel h2{font-size:clamp(21px,1.75vw,30px)}\n.hero p,.panel p,.mission-panel p{margin:10px 0 0;color:var(--muted);line-height:1.55}\n.hero-pills{display:flex;flex-wrap:wrap;gap:9px;justify-content:flex-end}\n.hero-pill,.status-pill{display:inline-flex;align-items:center;justify-content:center;min-height:34px;padding:8px 14px;border-radius:999px;border:1px solid var(--border-soft);font-weight:950;white-space:nowrap;background:rgba(148,163,184,.06)}\n.cyan{color:var(--cyan);border-color:rgba(0,212,255,.35)}.blue{color:var(--blue);border-color:rgba(96,165,250,.35)}.red{color:var(--red);border-color:rgba(248,113,113,.35)}.orange{color:var(--orange);border-color:rgba(251,146,60,.35)}.green{color:var(--green);border-color:rgba(34,197,94,.35)}.amber{color:var(--amber);border-color:rgba(245,158,11,.35)}\n\n.mission-panel{display:flex;align-items:flex-start;justify-content:space-between;gap:18px;padding:28px;margin-bottom:20px}\n.mission-copy{min-width:0}.mission-actions{display:flex;gap:10px;flex-wrap:wrap;justify-content:flex-end}\n.primary-button,.secondary-button{border-radius:18px;padding:14px 20px;font-weight:950;font-size:14px;cursor:pointer}\n.primary-button{border:1px solid rgba(0,212,255,.45);background:rgba(0,212,255,.09);color:#e8fbff}.primary-button:hover{background:rgba(0,212,255,.15)}\n.secondary-button{border:1px solid rgba(148,163,184,.24);background:rgba(148,163,184,.06);color:#cbd5e1}\n\n.panel{position:relative;width:100%;height:auto;min-height:0;overflow:visible;padding:28px;margin-bottom:20px}\n.panel-header{display:flex;align-items:flex-start;justify-content:space-between;gap:18px;flex-wrap:wrap;margin-bottom:22px}\n.purple-text{color:var(--purple)}.red-text{color:var(--red)}.orange-text{color:var(--orange)}\n.brief-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:14px}\n.brief-grid.two{grid-template-columns:repeat(auto-fit,minmax(260px,1fr))}.brief-grid.three{grid-template-columns:repeat(auto-fit,minmax(250px,1fr))}\n.brief-card{min-height:118px;padding:16px;border:1px solid var(--border-soft);border-radius:18px;background:rgba(15,23,42,.50);overflow-wrap:anywhere}\n.brief-card.primary{border-color:rgba(0,212,255,.34);background:linear-gradient(135deg,rgba(0,212,255,.08),rgba(15,23,42,.50))}\n.brief-card.wide{grid-column:1 / -1}\n.card-label{color:var(--muted);font-size:11px;letter-spacing:.13em;text-transform:uppercase;margin-bottom:9px}\n.card-value{color:#f8fafc;font-size:19px;font-weight:950;line-height:1.35}.card-value.small{font-size:16px;font-weight:850}\n.card-note{margin-top:10px;color:#9fb0c6;font-size:13px;line-height:1.45}\n\n.route-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(270px,1fr));gap:14px}\n.route-card{position:relative;padding:20px;border-radius:20px;border:1px solid var(--border-soft);background:rgba(15,23,42,.46);min-height:220px}\n.route-card h3{margin:14px 0 8px;color:#f8fafc;font-family:var(--font-display);font-size:18px;letter-spacing:.06em}\n.route-card p{font-size:13px}.route-card.blue{border-color:rgba(96,165,250,.25)}.route-card.red{border-color:rgba(248,113,113,.25)}.route-card.orange{border-color:rgba(251,146,60,.25)}\n.route-badge{display:inline-flex;border:1px solid rgba(148,163,184,.24);border-radius:999px;padding:6px 10px;color:#cbd5e1;text-transform:uppercase;letter-spacing:.1em;font-size:10px;font-weight:900}\n.route-state{position:absolute;left:20px;right:20px;bottom:18px;padding:10px 12px;border:1px solid rgba(148,163,184,.16);border-radius:14px;color:#f8fafc;font-weight:900;background:rgba(2,6,23,.35)}\n.route-card.selected{box-shadow:0 0 32px rgba(0,212,255,.14);border-color:rgba(0,212,255,.48)}\n\n.operator-grid{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:20px}\n.operator-card-list{display:grid;gap:12px}\n.operator-card{padding:14px;border:1px solid var(--border-soft);border-radius:16px;background:rgba(15,23,42,.48)}\n.operator-card-title{color:#f8fafc;font-weight:950;margin-bottom:7px}.operator-card-text{color:var(--muted);line-height:1.5}\n\n.trust-panel{border-color:rgba(34,197,94,.22)}.continuity-panel{border-color:rgba(192,132,252,.30);background:linear-gradient(135deg,rgba(17,10,34,.94),rgba(22,14,39,.88))}\n\n.diagnostics{display:none;margin:20px 0;border:1px solid rgba(148,163,184,.14);border-radius:16px;background:rgba(2,6,23,.34);padding:14px 18px}\n.diagnostics.open{display:block}\n.diagnostics summary{cursor:pointer;color:var(--muted);font-weight:900}\n.diagnostic-grid{display:grid;gap:10px;margin-top:14px}.diagnostic-grid code{display:block;padding:14px;border:1px solid var(--border-soft);border-radius:14px;background:rgba(2,6,23,.48);color:#c7f9ff;white-space:pre-wrap;overflow-wrap:anywhere}\n#diagnostic-json{margin-top:14px;white-space:pre-wrap;max-height:360px;overflow:auto;color:#93c5fd}\n\n.proofbar{position:sticky;bottom:16px;z-index:20;display:grid;grid-template-columns:repeat(5,minmax(0,1fr));border:1px solid var(--border);border-radius:20px;background:rgba(7,14,27,.96);backdrop-filter:blur(14px);overflow:hidden}\n.proofbar div{padding:14px 16px;border-right:1px solid rgba(148,163,184,.12)}.proofbar div:last-child{border-right:0}\n.proofbar span{display:block;color:var(--muted);text-transform:uppercase;letter-spacing:.12em;font-size:10px;margin-bottom:6px}.proofbar strong{display:block;color:#f8fafc;font-size:14px;overflow-wrap:anywhere}\n\n@media (max-width:1320px){.claire-app{grid-template-columns:360px minmax(0,1fr);padding:16px}.operator-grid{grid-template-columns:1fr}.hero,.mission-panel{flex-direction:column}.hero-pills,.mission-actions{justify-content:flex-start}}\n@media (max-width:920px){.claire-app{grid-template-columns:1fr}.claire-sidebar{position:relative;top:auto;max-height:none}.proofbar{position:relative;bottom:auto;grid-template-columns:1fr 1fr}}\n', 'src/frontend/command_center/modern/claire_strategic_cockpit.js': '(function () {\n  "use strict";\n\n  const PATHS = {\n    runtime: [\n      "../../../exports/latest/dashboard_runtime_truth.json",\n      "exports/latest/dashboard_runtime_truth.json",\n      "runtime_truth_status.json",\n      "./runtime_truth_status.json"\n    ],\n    validation: [\n      "../../../exports/latest/validation_authority_report.json",\n      "exports/latest/validation_authority_report.json",\n      "validation_authority_status.json",\n      "./validation_authority_status.json"\n    ],\n    evidence: [\n      "../../../exports/latest/evidence_traceability_index.json",\n      "exports/latest/evidence_traceability_index.json",\n      "evidence_traceability_status.json",\n      "./evidence_traceability_status.json"\n    ],\n    memory: [\n      "../../../exports/latest/verified_memory_gate_report.json",\n      "exports/latest/verified_memory_gate_report.json",\n      "verified_memory_status.json",\n      "./verified_memory_status.json"\n    ],\n    feedback: [\n      "../../../exports/latest/recursive_feedback_gate_report.json",\n      "exports/latest/recursive_feedback_gate_report.json",\n      "recursive_feedback_status.json",\n      "./recursive_feedback_status.json"\n    ],\n    search: [\n      "dashboard_search_index.json",\n      "./dashboard_search_index.json",\n      "../../../exports/latest/dashboard_search_index.json",\n      "exports/latest/dashboard_search_index.json"\n    ],\n    registries: [\n      "dashboard_architecture_map.json",\n      "lifecycle_stage_registry.json",\n      "runtime_surface_registry.json",\n      "route_surface_registry.json",\n      "dashboard_search_contract.json",\n      "intelligence_command_contract.json"\n    ]\n  };\n\n  let searchDocs = [];\n  let latestSnapshot = {};\n\n  function $(id) { return document.getElementById(id); }\n  function normalize(value) { return String(value ?? "").replace(/\\s+/g, " ").trim(); }\n  function lower(value) { return normalize(value).toLowerCase(); }\n  function escapeHtml(value) {\n    return String(value ?? "")\n      .replace(/&/g, "&amp;").replace(/</g, "&lt;")\n      .replace(/>/g, "&gt;").replace(/"/g, "&quot;");\n  }\n\n  async function fetchJson(path) {\n    try {\n      const response = await fetch(path, { cache: "no-store" });\n      if (!response.ok) return null;\n      return await response.json();\n    } catch (_) { return null; }\n  }\n\n  async function fetchFirst(paths) {\n    for (const path of paths) {\n      const json = await fetchJson(path);\n      if (json) return { path, json };\n    }\n    return { path: "", json: null };\n  }\n\n  function first(obj, keys, fallback = "") {\n    if (!obj || typeof obj !== "object") return fallback;\n    for (const key of keys) {\n      const value = obj[key];\n      if (value !== undefined && value !== null && value !== "") return value;\n    }\n    return fallback;\n  }\n\n  function section(obj, key) {\n    const value = obj?.[key];\n    return value && typeof value === "object" && !Array.isArray(value) ? value : {};\n  }\n\n  function setText(id, value) {\n    const node = $(id);\n    if (node) node.textContent = value ?? "";\n  }\n\n  function flattenJson(value, prefix = "") {\n    const rows = [];\n    function walk(node, path) {\n      if (node === null || node === undefined) return;\n      if (Array.isArray(node)) {\n        node.forEach((item, index) => walk(item, `${path}[${index}]`));\n        return;\n      }\n      if (typeof node === "object") {\n        Object.entries(node).forEach(([key, item]) => walk(item, path ? `${path}.${key}` : key));\n        return;\n      }\n      rows.push(`${path}: ${String(node)}`);\n    }\n    walk(value, prefix);\n    return rows.join("\\n");\n  }\n\n  function friendlyPath(route) {\n    const r = lower(route);\n    if (!r) return "Awaiting signal";\n    if (r.includes("portfolio")) return "Portfolio intelligence";\n    if (r.includes("breakthrough") || r.includes("design") || r.includes("autodesign") || r.includes("system")) return "Breakthrough / design";\n    if (r.includes("acquisition") || r.includes("package")) return "Acquisition package";\n    if (r.includes("blocked")) return "Blocked";\n    if (r.includes("insufficient")) return "Insufficient data";\n    return String(route).replace(/_/g, " ");\n  }\n\n  function friendlyTerminal(state) {\n    const s = lower(state);\n    const map = {\n      "trend_thesis_ready": "Thesis ready",\n      "portfolio_action_ready": "Portfolio action ready",\n      "portfolio_optimization_ready": "Portfolio optimization ready",\n      "discovery_ready": "Discovery ready",\n      "breakthrough_classified": "Breakthrough classified",\n      "advancement_path_selected": "Advancement path selected",\n      "design_output_ready": "Design output ready",\n      "acquisition_ready": "Acquisition ready",\n      "acquisition_package_ready": "Acquisition package ready",\n      "final_package_ready": "Final package ready",\n      "insufficient_data": "Insufficient data",\n      "blocked": "Blocked",\n      "failed": "Failed",\n      "max_iterations_reached": "Max iterations reached"\n    };\n    return map[s] || (s ? String(state).replace(/_/g, " ") : "Not ready");\n  }\n\n  function friendlyTrust(status) {\n    const s = lower(status);\n    if (["pass", "passed", "verified", "valid"].includes(s)) return "Verified";\n    if (["fail", "failed", "invalid"].includes(s)) return "Failed";\n    if (["blocked"].includes(s)) return "Blocked";\n    return "Unverified";\n  }\n\n  function friendlyMemory(status) {\n    const s = lower(status);\n    if (["eligible", "allowed", "pass", "passed"].includes(s)) return "Ready";\n    if (["blocked", "failed"].includes(s)) return "Blocked";\n    return "Not ready";\n  }\n\n  function statusClass(status) {\n    const s = lower(status);\n    if (["verified", "ready", "eligible", "allowed", "loaded", "portfolio action ready", "acquisition package ready", "final package ready"].includes(s)) return "green";\n    if (["failed", "blocked"].includes(s)) return "red";\n    if (["unverified", "not ready", "awaiting mission", "awaiting signal", "no mission loaded", "not selected"].includes(s)) return "amber";\n    if (s.includes("portfolio")) return "blue";\n    if (s.includes("breakthrough") || s.includes("design")) return "red";\n    if (s.includes("acquisition")) return "orange";\n    return "cyan";\n  }\n\n  function applyPill(id, value) {\n    const node = $(id);\n    if (!node) return;\n    node.textContent = value;\n    node.className = `status-pill ${statusClass(value)}`;\n  }\n\n  function card(title, text) {\n    return `<div class="operator-card"><div class="operator-card-title">${escapeHtml(title)}</div><div class="operator-card-text">${escapeHtml(text)}</div></div>`;\n  }\n\n  async function loadCockpit() {\n    const runtime = await fetchFirst(PATHS.runtime);\n    const validation = await fetchFirst(PATHS.validation);\n    const evidence = await fetchFirst(PATHS.evidence);\n    const memory = await fetchFirst(PATHS.memory);\n    const feedback = await fetchFirst(PATHS.feedback);\n\n    latestSnapshot = { runtime, validation, evidence, memory, feedback };\n\n    const r = runtime.json || {};\n    const run = section(r, "run_truth");\n    const route = section(r, "route_truth");\n    const terminal = section(r, "terminal_truth");\n    const stage = section(r, "stage_truth");\n    const output = section(r, "output_truth");\n    const validationJson = validation.json || {};\n    const evidenceJson = evidence.json || {};\n    const memoryJson = memory.json || {};\n    const feedbackJson = feedback.json || {};\n\n    const rawRunId = first(validationJson, ["run_id"], first(run, ["run_id", "id"], first(r, ["run_id"], "")));\n    const rawRoute = first(validationJson, ["route_selected"], first(route, ["route_selected", "selected_route"], first(run, ["selected_route"], "")));\n    const rawTerminal = first(validationJson, ["terminal_state"], first(terminal, ["terminal_state", "state"], first(run, ["terminal_state"], "")));\n    const rawTrust = first(validationJson, ["validation_authority_status", "validation_status"], "");\n    const rawMemory = first(memoryJson, ["memory_status"], "");\n\n    const mission = rawRunId || "No mission loaded";\n    const path = friendlyPath(rawRoute);\n    const readiness = friendlyTerminal(rawTerminal);\n    const trust = friendlyTrust(rawTrust);\n    const continuity = friendlyMemory(rawMemory);\n\n    const stages = first(stage, ["stages_total", "total_stages"], Array.isArray(stage.stages) ? String(stage.stages.length) : "Not loaded");\n    const trustScore = first(validationJson, ["validation_score"], 0);\n    const evidenceCount = first(evidenceJson, ["evidence_count"], first(validationJson.evidence_summary || {}, ["evidence_count"], 0));\n    const unsupportedCount = first(evidenceJson, ["unsupported_count"], first(validationJson.evidence_summary || {}, ["unsupported_count"], 0));\n    const memoryEligible = first(memoryJson, ["memory_eligible"], false) ? "Eligible" : "Blocked";\n    const feedbackAllowed = first(feedbackJson, ["recursive_feedback_allowed"], false) ? "Allowed" : "Blocked";\n\n    const thesis = first(output, ["thesis", "strategic_thesis", "insight", "summary"], first(r, ["thesis", "strategic_thesis", "summary"], "No thesis available"));\n    const signalState = runtime.json ? "Signal data loaded" : "Awaiting signal";\n    const review = trust === "Verified" ? "Review package for action" : "Verify before action";\n\n    setText("side-mission", mission);\n    setText("side-path", path);\n    setText("side-readiness", readiness);\n    setText("side-trust", trust);\n\n    setText("mission-title", runtime.json ? "Mission loaded" : "No active mission loaded");\n    setText("mission-summary", runtime.json ? `Claire has loaded mission ${mission}. Review the path, trust gate, and strategic package before acting.` : "Claire is ready, but no completed mission output has been loaded into the cockpit yet.");\n\n    setText("brief-objective", runtime.json ? readiness : "Load or generate a Claire mission");\n    setText("brief-objective-note", runtime.json ? `Mission: ${mission}` : "The cockpit will not invent an opportunity without a run output.");\n    setText("brief-thesis", thesis);\n    setText("brief-signal", signalState);\n    setText("brief-review", review);\n\n    setText("acq-package", path.includes("Acquisition") || readiness.includes("Acquisition") || readiness.includes("Final") ? readiness : "No package loaded");\n    setText("acq-fit", path.includes("Acquisition") ? "Review required" : "Not evaluated");\n    setText("acq-rationale", path.includes("Acquisition") ? "Loaded from acquisition path when available" : "Not available");\n\n    setText("trust-score", `${trustScore}/100`);\n    setText("trust-evidence", `${evidenceCount} item(s)`);\n    setText("trust-message", validationJson.blocking_failures?.[0]?.details || validationJson.message || (trust === "Verified" ? "Output passed verification." : "No verified mission output loaded."));\n\n    setText("continuity-state", continuity);\n    setText("future-use", feedbackAllowed);\n    setText("continuity-reason", memoryJson.memory_reasons?.[0] || feedbackJson.feedback_reasons?.[0] || "Claire needs verified output before continuity can be enabled.");\n\n    setText("proof-mission", mission);\n    setText("proof-path", path);\n    setText("proof-readiness", readiness);\n    setText("proof-trust", trust);\n    setText("proof-continuity", continuity);\n\n    applyPill("brief-pill", runtime.json ? "Mission loaded" : "Awaiting mission");\n    applyPill("path-pill", path);\n    applyPill("acquisition-pill", path.includes("Acquisition") || readiness.includes("Acquisition") || readiness.includes("Final") ? "Package review" : "Not ready");\n    applyPill("trust-pill", trust);\n    applyPill("continuity-pill", continuity);\n\n    updateRoutes(path);\n    renderOperatorLists({ runtime, validation, memory, feedback, mission, path, readiness, trust, continuity, stages, evidenceCount, unsupportedCount, memoryEligible, feedbackAllowed });\n    renderDiagnostics();\n  }\n\n  function updateRoutes(path) {\n    const cards = ["route-portfolio", "route-breakthrough", "route-acquisition"];\n    cards.forEach((id) => $(id)?.classList.remove("selected"));\n\n    setText("route-portfolio-state", "Available");\n    setText("route-breakthrough-state", "Not selected");\n    setText("route-acquisition-state", "Not selected");\n\n    if (path.includes("Portfolio")) {\n      $("route-portfolio")?.classList.add("selected");\n      setText("route-portfolio-state", "Selected");\n    } else if (path.includes("Breakthrough") || path.includes("design")) {\n      $("route-breakthrough")?.classList.add("selected");\n      setText("route-breakthrough-state", "Selected");\n    } else if (path.includes("Acquisition")) {\n      $("route-acquisition")?.classList.add("selected");\n      setText("route-acquisition-state", "Selected");\n    } else {\n      setText("route-portfolio-state", "Default when signal qualifies");\n    }\n  }\n\n  function renderOperatorLists(state) {\n    const portfolio = $("portfolio-content");\n    if (portfolio) {\n      portfolio.innerHTML = [\n        card("Portfolio recommendation", state.path.includes("Portfolio") ? state.readiness : "No portfolio action loaded yet."),\n        card("Evidence basis", `${state.evidenceCount} evidence item(s), ${state.unsupportedCount} unsupported item(s).`),\n        card("Operator rule", "Do not act on a portfolio recommendation until trust is verified.")\n      ].join("");\n    }\n\n    const breakthrough = $("breakthrough-content");\n    if (breakthrough) {\n      const active = state.path.includes("Breakthrough") || state.path.includes("design");\n      breakthrough.innerHTML = [\n        card("Design route", active ? state.readiness : "No breakthrough/design path selected."),\n        card("Stages 16–22", "Auto invention, solution structuring, buildability, viability, manufacturability, feasibility, and design portal output remain preserved for design paths."),\n        card("Operator rule", "Design outputs require feasibility and trust review before packaging.")\n      ].join("");\n    }\n\n    const actions = $("action-list");\n    if (actions) {\n      const items = [];\n      if (!state.runtime.json) items.push(card("Load a mission", "Generate or expose a completed Claire output so the cockpit can display a real opportunity."));\n      if (state.runtime.json && state.trust !== "Verified") items.push(card("Verify before action", "The current mission is loaded but not yet trusted. Run verification before treating it as operator-ready."));\n      if (state.trust === "Verified" && state.continuity !== "Ready") items.push(card("Decide continuity", "The output is verified. Check whether it should become continuity for future Claire reasoning."));\n      if (state.path.includes("Acquisition")) items.push(card("Review acquisition package", "Inspect moat, acquirer fit, strategic rationale, and final package readiness."));\n      if (!items.length) items.push(card("Review final package", "The cockpit has loaded the available mission, path, trust, and continuity state."));\n      actions.innerHTML = items.join("");\n    }\n  }\n\n  function renderDiagnostics() {\n    const node = $("diagnostic-json");\n    if (node) node.textContent = JSON.stringify(latestSnapshot, null, 2);\n  }\n\n  function addDoc(doc) {\n    const key = `${doc.type}:${doc.path}:${doc.title}`;\n    if (searchDocs.some((d) => `${d.type}:${d.path}:${d.title}` === key)) return;\n    searchDocs.push(doc);\n  }\n\n  async function buildSearchDocs() {\n    searchDocs = [];\n    document.querySelectorAll("section, aside, header, footer, details").forEach((node, index) => {\n      const text = normalize(node.innerText || node.textContent || "");\n      if (!text || text.length < 18) return;\n      if (!node.id) node.id = `cockpit-search-section-${index}`;\n      const title = normalize(node.querySelector("h1,h2,h3,.panel-kicker,summary")?.textContent || node.id);\n      addDoc({ type: "workspace", title, path: `#${node.id}`, text, targetId: node.id });\n    });\n\n    for (const group of Object.values(PATHS)) {\n      for (const path of group) {\n        const json = await fetchJson(path);\n        if (!json) continue;\n        if (json.schema === "claire.dashboard_intelligence_index.v1" && Array.isArray(json.documents)) {\n          json.documents.forEach((doc) => {\n            if (doc.status && doc.status !== "indexed") return;\n            addDoc({ type: "index", title: doc.title || doc.path || path, path: doc.path || path, text: doc.text || (doc.terms || []).join(" "), json: doc });\n          });\n        }\n        addDoc({ type: "local data", title: path.split("/").pop() || path, path, text: flattenJson(json), json });\n      }\n    }\n  }\n\n  function search(query) {\n    const parts = lower(query).split(" ").filter(Boolean);\n    if (!parts.length) return [];\n    return searchDocs.map((doc) => {\n      const hay = `${doc.title}\\n${doc.path}\\n${doc.text}`.toLowerCase();\n      let score = 0;\n      parts.forEach((p) => {\n        if (doc.title.toLowerCase().includes(p)) score += 12;\n        if (doc.path.toLowerCase().includes(p)) score += 6;\n        score += Math.min(hay.split(p).length - 1, 12);\n      });\n      return { doc, score };\n    }).filter((x) => x.score > 0).sort((a, b) => b.score - a.score).slice(0, 10);\n  }\n\n  function snippet(text, query) {\n    const clean = normalize(text);\n    const parts = lower(query).split(" ").filter(Boolean);\n    const hay = clean.toLowerCase();\n    let idx = -1;\n    for (const p of parts) {\n      idx = hay.indexOf(p);\n      if (idx >= 0) break;\n    }\n    if (idx < 0) return clean.slice(0, 220);\n    const start = Math.max(0, idx - 80);\n    const end = Math.min(clean.length, idx + 180);\n    return `${start > 0 ? "…" : ""}${clean.slice(start, end)}${end < clean.length ? "…" : ""}`;\n  }\n\n  function setupSearch() {\n    const input = $("claire-search-input");\n    const results = $("claire-search-results");\n    if (!input || !results) return;\n\n    input.addEventListener("input", () => {\n      const query = input.value.trim();\n      if (!query) {\n        results.classList.remove("open");\n        results.innerHTML = "";\n        return;\n      }\n      const matches = search(query);\n      results.classList.add("open");\n      if (!matches.length) {\n        results.innerHTML = `<div class="search-result-snippet" style="padding:12px;">No local matches. Claire is searching only loaded workspace and local mission data.</div>`;\n        return;\n      }\n      results.innerHTML = matches.map(({ doc }) => `\n        <button class="search-result" type="button">\n          <div class="search-result-title">${escapeHtml(doc.title)}</div>\n          <div class="search-result-meta">${escapeHtml(doc.type)} · ${escapeHtml(doc.path)}</div>\n          <div class="search-result-snippet">${escapeHtml(snippet(doc.text, query))}</div>\n        </button>\n      `).join("");\n\n      Array.from(results.querySelectorAll(".search-result")).forEach((button, index) => {\n        button.addEventListener("click", () => {\n          const doc = matches[index].doc;\n          results.classList.remove("open");\n          if (doc.targetId) {\n            const target = document.getElementById(doc.targetId);\n            if (target) target.scrollIntoView({ behavior: "smooth", block: "start" });\n          }\n        });\n      });\n    });\n\n    document.addEventListener("keydown", (event) => {\n      if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "k") {\n        event.preventDefault();\n        input.focus();\n        input.select();\n      }\n      if ((event.ctrlKey || event.metaKey) && event.shiftKey && event.key.toLowerCase() === "d") {\n        event.preventDefault();\n        $("developer-diagnostics")?.classList.toggle("open");\n      }\n    });\n\n    document.addEventListener("click", (event) => {\n      if (!$("claire-search")?.contains(event.target)) results.classList.remove("open");\n    });\n  }\n\n  function setupMic() {\n    const button = $("claire-mic-button");\n    const input = $("claire-search-input");\n    if (!button || !input) return;\n    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;\n    if (!SpeechRecognition) {\n      button.disabled = true;\n      button.title = "Microphone search is not supported in this browser.";\n      return;\n    }\n    const recognition = new SpeechRecognition();\n    recognition.continuous = false;\n    recognition.interimResults = false;\n    recognition.lang = navigator.language || "en-US";\n    recognition.onstart = () => button.classList.add("listening");\n    recognition.onend = () => button.classList.remove("listening");\n    recognition.onerror = () => button.classList.remove("listening");\n    recognition.onresult = (event) => {\n      const transcript = Array.from(event.results || []).map((r) => r[0]?.transcript || "").join(" ").trim();\n      if (transcript) {\n        input.value = transcript;\n        input.dispatchEvent(new Event("input", { bubbles: true }));\n        input.focus();\n      }\n    };\n    button.addEventListener("click", () => {\n      try { recognition.start(); } catch (_) {}\n    });\n  }\n\n  function setupNav() {\n    const links = document.querySelectorAll(".nav-item");\n    links.forEach((link) => {\n      link.addEventListener("click", () => {\n        links.forEach((other) => other.classList.remove("active"));\n        link.classList.add("active");\n      });\n    });\n  }\n\n  async function boot() {\n    setupSearch();\n    setupMic();\n    setupNav();\n    await loadCockpit();\n    await buildSearchDocs();\n\n    $("refresh-state")?.addEventListener("click", async () => {\n      const button = $("refresh-state");\n      button.textContent = "Refreshing…";\n      await loadCockpit();\n      await buildSearchDocs();\n      button.textContent = "Refresh Cockpit";\n    });\n\n    $("diagnostics-toggle")?.addEventListener("click", () => {\n      $("developer-diagnostics")?.classList.toggle("open");\n      $("developer-diagnostics")?.scrollIntoView({ behavior: "smooth", block: "start" });\n    });\n  }\n\n  if (document.readyState === "loading") {\n    document.addEventListener("DOMContentLoaded", boot);\n  } else {\n    boot();\n  }\n})();\n', 'src/frontend/command_center/modern/operator_surface_contract.json': '{\n  "schema": "claire.operator_surface_contract.v1",\n  "version": "17.62.8",\n  "purpose": "Define operator-facing cockpit surfaces for Claire Syntalion.",\n  "operator_surfaces": [\n    "Mission Control",\n    "Opportunity Brief",\n    "Strategic Path",\n    "Portfolio Desk",\n    "Breakthrough Studio",\n    "Acquisition Room",\n    "Trust Gate",\n    "Continuity",\n    "Next Operator Actions"\n  ],\n  "developer_surfaces": [\n    "Developer diagnostics"\n  ],\n  "rules": [\n    "Main dashboard must not launch as a developer/runtime monitor.",\n    "Technical statuses must be translated to operator language.",\n    "Developer diagnostics must remain collapsed or secondary.",\n    "No fake mission, opportunity, route, evidence, trust, or continuity data may be invented.",\n    "Dashboard reads existing runtime truth, validation, evidence, memory, and feedback files only."\n  ],\n  "status_translation_examples": {\n    "not_loaded": "No mission loaded",\n    "missing": "Not ready",\n    "not_generated": "Unverified or Not ready",\n    "pass": "Verified",\n    "blocked": "Blocked"\n  }\n}\n', 'docs/dashboard/v17.62.8_strategic_operator_cockpit.md': '# Claire v17.62.8 — Strategic Operator Cockpit\n\n## Purpose\n\nv17.62.8 converts the dashboard from an operator-labeled developer console into a true strategic cockpit.\n\nThe main surface now reflects Claire\'s actual category:\nAutonomous Strategic Intelligence & Acquisition Construction Platform.\n\n## Operator surfaces\n\n```text\nMission Control\nOpportunity Brief\nStrategic Path\nPortfolio Desk\nBreakthrough Studio\nAcquisition Room\nTrust Gate\nContinuity\nNext Operator Actions\n```\n\n## Developer material\n\nDeveloper commands and raw diagnostics are moved into a hidden/collapsed diagnostics section.\n\nShortcut:\n\n```text\nCtrl + Shift + D\n```\n\n## What changed\n\n- Removed "Runtime Truth Stack" from the main UI.\n- Removed "Validation Authority" from the main UI.\n- Removed "Verified Memory" from the main UI.\n- Replaced them with operator-facing equivalents:\n  - Decision/path → Strategic Path\n  - Verification → Trust Gate\n  - Memory/recursion → Continuity\n  - Acquisition outputs → Acquisition Room\n  - Design route → Breakthrough Studio\n- Preserved honest missing-data behavior.\n\n## Scope\n\nNo backend logic changed.\nNo runtime logic changed.\nNo validation logic changed.\nNo memory logic changed.\nNo fake data added.\n', 'docs/update_packs/v17.62.8_strategic_operator_cockpit_pack.md': '# v17.62.8 Dashboard Update Pack — Strategic Operator Cockpit\n\n## Architecture references\n\nThis build aligns the dashboard to Claire\'s master definition as an Autonomous Strategic Intelligence & Acquisition Construction Platform and to the Complete Systems Flow signal-to-memory / route execution model.\n\n## Verification\n\nAfter install:\n\n1. Hard refresh with Ctrl+F5.\n2. Confirm the title says "Strategic Operator Cockpit".\n3. Confirm main sections are Mission Control, Opportunity Brief, Strategic Path, Portfolio Desk, Breakthrough Studio, Acquisition Room, Trust Gate, Continuity.\n4. Confirm no main section says Runtime Truth Stack, Validation Authority, or Verified Memory.\n5. Confirm developer diagnostics are hidden/collapsed.\n6. Confirm missing data is shown honestly.\n', 'data/build_manifests/v17.62.8_strategic_operator_cockpit_manifest.json': '{\n  "version": "17.62.8",\n  "name": "Strategic Operator Cockpit",\n  "build_type": "dashboard_operator_cockpit",\n  "purpose": "Replace dev-oriented operator shell with a strategic intelligence/acquisition cockpit.",\n  "installed_files": [\n    "docs/dashboard/v17.62.8_strategic_operator_cockpit.md",\n    "docs/update_packs/v17.62.8_strategic_operator_cockpit_pack.md",\n    "src/frontend/command_center/modern/claire_strategic_cockpit.css",\n    "src/frontend/command_center/modern/claire_strategic_cockpit.js",\n    "src/frontend/command_center/modern/index.html",\n    "src/frontend/command_center/modern/operator_surface_contract.json"\n  ],\n  "replaces": [\n    "src/frontend/command_center/modern/index.html",\n    "src/frontend/command_center/modern/claire_strategic_cockpit.css",\n    "src/frontend/command_center/modern/claire_strategic_cockpit.js"\n  ],\n  "safety": {\n    "rollback_backups": true,\n    "launcher_path_preserved": "src/frontend/command_center/modern/index.html",\n    "runtime_logic_unchanged": true,\n    "validation_logic_unchanged": true,\n    "memory_logic_unchanged": true,\n    "no_fake_data": true,\n    "developer_diagnostics_collapsed": true\n  }\n}\n'}

def utc_stamp() -> str:
    return datetime.utcnow().strftime("%Y%m%d_%H%M%S")

def project_root() -> Path:
    return Path.cwd().resolve()

def backup_existing(root: Path, relative_path: str, backup_root: Path) -> None:
    target = root / relative_path
    if not target.exists():
        return
    backup_path = backup_root / relative_path
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    if target.is_file():
        shutil.copy2(target, backup_path)
    elif target.is_dir():
        if backup_path.exists():
            shutil.rmtree(backup_path)
        shutil.copytree(target, backup_path)

def write_text(root: Path, relative_path: str, content: str, backup_root: Path) -> None:
    target = root / relative_path
    backup_existing(root, relative_path, backup_root)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")

def write_install_record(root: Path, backup_root: Path) -> None:
    record = {
        "version": VERSION,
        "build_name": BUILD_NAME,
        "installed_at_utc": datetime.utcnow().isoformat() + "Z",
        "project_root": str(root),
        "backup_root": str(backup_root),
        "files_written": sorted(FILES.keys()),
        "notes": [
            "Replaced main UI with strategic operator cockpit surfaces.",
            "Developer diagnostics moved to collapsed section.",
            "Runtime, validation, evidence, memory, and feedback data are still read honestly.",
            "No backend/runtime logic changed."
        ]
    }
    record_path = root / "data" / "build_manifests" / "v17.62.8_install_record.json"
    record_path.parent.mkdir(parents=True, exist_ok=True)
    record_path.write_text(json.dumps(record, indent=2) + "\n", encoding="utf-8")

def main() -> None:
    root = project_root()
    backup_root = root / "backups" / f"claire_v17_62_8_{utc_stamp()}"
    backup_root.mkdir(parents=True, exist_ok=True)

    for relative_path, content in FILES.items():
        write_text(root, relative_path, content, backup_root)

    write_install_record(root, backup_root)

    print("=" * 72)
    print(f"Claire v{VERSION} installed: {BUILD_NAME}")
    print("=" * 72)
    print(f"Project root: {root}")
    print(f"Backups:      {backup_root}")
    print("")
    print("Installed strategic operator cockpit:")
    print("  - Mission Control")
    print("  - Opportunity Brief")
    print("  - Strategic Path")
    print("  - Portfolio Desk")
    print("  - Breakthrough Studio")
    print("  - Acquisition Room")
    print("  - Trust Gate")
    print("  - Continuity")
    print("")
    print("Hard refresh the dashboard with Ctrl+F5.")
    print("=" * 72)

if __name__ == "__main__":
    main()
